/**
 * @fileoverview MarkdownEditor events — centralised event binding,
 *               keyboard shortcuts, toolbar / WYSIWYG actions, and
 *               text manipulation helpers.
 * @module module/MarkdownEditor/events
 */

import { getCustomTools, PART } from './constants.js';
import razyui from '../../index.js';
import Icons from '../Icons.js';
import { parse, htmlToMarkdown } from './helpers.js';

// ═══════════════════════════════════════════════════
// Event Binding
// ═══════════════════════════════════════════════════

/**
 * Attach all event listeners for the editor.
 * @param {object} ctx — context bridge
 */
export function bindEvents(ctx) {
    const globalOpts = ctx.signal ? { signal: ctx.signal } : undefined;

    // ── Delegated toolbar & context-menu events (all modes) ──
    bindToolbarAndMenuEvents(ctx);

    if (ctx.config.lite) {
        // ── WYSIWYG mode (lite) — bind events on contenteditable preview ──
        const el = ctx.preview;
        el.on('input', () => onWysiwygInput(ctx))
          .on('keydown', (e) => handleKeydown(ctx, e));

        // Right-click context menu
        el.on('contextmenu', (e) => {
            e.preventDefault();
            saveSelection(ctx);
            ctx.showContextMenu(e.clientX, e.clientY);
        });

        // Dismiss context menu & history menu
        razyui(document).on('mousedown', (e) => {
            if (ctx.contextMenu && ctx.contextMenu.css('display') === 'block' &&
                !ctx.contextMenu.contains(e.target)) {
                ctx.hideContextMenu();
            }
            // Close history dropdown if clicking outside
            const histMenu = ctx.toolbar?.find('.md-history-menu.is-open');
            if (histMenu?.length && !e.target.closest('.md-history-menu-wrap')) {
                histMenu.removeClass('is-open');
            }
        }, globalOpts);
        razyui(document).on('keydown', (e) => {
            if (e.key === 'Escape') {
                ctx.hideContextMenu();
                ctx.toolbar?.find('.md-history-menu.is-open')?.removeClass('is-open');
            }
        }, globalOpts);
        return;
    }

    const ta = ctx.textarea;

    // ── Input → debounced preview update ──
    ta.on('input', () => onInput(ctx));

    // ── Keyboard shortcuts ──
    ta.on('keydown', (e) => handleKeydown(ctx, e));

    // ── Sync scroll ──
    ta.on('scroll', () => {
        if (ctx.stateRef.mode !== 'split') return;
        const ratio = ta.prop('scrollTop') / Math.max(1, ta.prop('scrollHeight') - ta.prop('clientHeight'));
        const previewParent = ctx.preview.parent()[0];
        previewParent.scrollTop =
            ratio * Math.max(0, previewParent.scrollHeight - previewParent.clientHeight);
    });

    // ── Tab key → indent ──
    ta.on('keydown', (e) => {
        if (e.key === 'Tab') {
            e.preventDefault();
            const start = ta[0].selectionStart;
            const end = ta[0].selectionEnd;
            if (e.shiftKey) {
                // Un-indent current line
                const text = ta.val();
                const lineStart = text.lastIndexOf('\n', start - 1) + 1;
                if (text.substring(lineStart, lineStart + 4) === '    ') {
                    ta.val(text.substring(0, lineStart) + text.substring(lineStart + 4));
                    ta[0].selectionStart = Math.max(lineStart, start - 4);
                    ta[0].selectionEnd = Math.max(lineStart, end - 4);
                } else if (text[lineStart] === '\t') {
                    ta.val(text.substring(0, lineStart) + text.substring(lineStart + 1));
                    ta[0].selectionStart = Math.max(lineStart, start - 1);
                    ta[0].selectionEnd = Math.max(lineStart, end - 1);
                }
            } else {
                // Insert 4 spaces
                ta.val(v => v.substring(0, start) + '    ' + v.substring(end));
                ta[0].selectionStart = ta[0].selectionEnd = start + 4;
            }
            onInput(ctx);
        }
    });

    // ── Right-click context menu ──
    ta.on('contextmenu', (e) => {
        if (ctx.stateRef.mode === 'preview') return;
        e.preventDefault();
        saveSelection(ctx);
        ctx.showContextMenu(e.clientX, e.clientY);
    });

    // ── Dismiss context menu & history menu on outside click ──
    razyui(document).on('mousedown', (e) => {
        if (ctx.contextMenu && ctx.contextMenu.css('display') === 'block' &&
            !ctx.contextMenu.contains(e.target)) {
            ctx.hideContextMenu();
        }
        // Close history dropdown if clicking outside
        const histMenu = ctx.toolbar?.find('.md-history-menu.is-open');
        if (histMenu?.length && !e.target.closest('.md-history-menu-wrap')) {
            histMenu.removeClass('is-open');
        }
    }, globalOpts);

    // ── Dismiss context menu & history menu on Escape ──
    razyui(document).on('keydown', (e) => {
        if (e.key === 'Escape') {
            ctx.hideContextMenu();
            ctx.toolbar?.find('.md-history-menu.is-open')?.removeClass('is-open');
        }
    }, globalOpts);

    // ── Dismiss context menu on scroll ──
    ta.on('scroll', () => ctx.hideContextMenu());

    // ── WYSIWYG events on preview (for non-lite mode switching) ──
    ctx.preview.on('input', () => {
        if (ctx.stateRef.mode === 'wysiwyg') onWysiwygInput(ctx);
    });
    ctx.preview.on('keydown', (e) => {
        if (ctx.stateRef.mode === 'wysiwyg') handleKeydown(ctx, e);
    });
    ctx.preview.on('contextmenu', (e) => {
        if (ctx.stateRef.mode === 'wysiwyg') {
            e.preventDefault();
            saveSelection(ctx);
            ctx.showContextMenu(e.clientX, e.clientY);
        }
    });
}

// ═══════════════════════════════════════════════════
// Keyboard Shortcuts
// ═══════════════════════════════════════════════════

/**
 * Handle keyboard shortcuts (Ctrl+B, Ctrl+I, Ctrl+K, Ctrl+E, Ctrl+S).
 * @param {object} ctx
 * @param {KeyboardEvent} e
 */
export function handleKeydown(ctx, e) {
    const ctrl = e.ctrlKey || e.metaKey;
    if (!ctrl) return;

    switch (e.key.toLowerCase()) {
        case 'b':
            e.preventDefault();
            handleAction(ctx, 'bold');
            break;
        case 'i':
            e.preventDefault();
            handleAction(ctx, 'italic');
            break;
        case 'k':
            e.preventDefault();
            handleAction(ctx, 'link');
            break;
        case 'e':
            e.preventDefault();
            handleAction(ctx, 'code');
            break;
        case 'm':
            e.preventDefault();
            handleAction(ctx, 'math');
            break;
        case 's':
            e.preventDefault();
            if (e.shiftKey) {
                handleAction(ctx, 'strikethrough');
            } else if (typeof ctx.config.onSave === 'function') {
                const md = ctx.textarea
                    ? ctx.textarea.val()
                    : htmlToMarkdown(ctx.preview.html());
                ctx.config.onSave(md);
            }
            break;
    }
}

// ═══════════════════════════════════════════════════
// Action Dispatcher
// ═══════════════════════════════════════════════════

/**
 * Execute a formatting action by name.
 * @param {object} ctx
 * @param {string} action
 */
export function handleAction(ctx, action) {
    // Block all formatting actions in preview mode
    if (ctx.stateRef.mode === 'preview') return;

    // WYSIWYG mode — use Selection / Range API
    if (ctx.stateRef.mode === 'wysiwyg' || ctx.config.lite) {
        handleWysiwygAction(ctx, action);
        return;
    }

    switch (action) {
        case 'bold':          wrapSelection(ctx, '**', '**'); break;
        case 'italic':        wrapSelection(ctx, '*', '*'); break;
        case 'strikethrough': wrapSelection(ctx, '~~', '~~'); break;
        case 'h1':            toggleLinePrefix(ctx, '# '); break;
        case 'h2':            toggleLinePrefix(ctx, '## '); break;
        case 'h3':            toggleLinePrefix(ctx, '### '); break;
        case 'ul':            toggleLinePrefix(ctx, '- '); break;
        case 'ol':            toggleLinePrefix(ctx, '1. '); break;
        case 'task':          toggleLinePrefix(ctx, '- [ ] '); break;
        case 'link':          insertLink(ctx); break;
        case 'image':         insertImage(ctx); break;
        case 'code':          wrapSelection(ctx, '`', '`'); break;
        case 'codeblock':     wrapBlock(ctx, '```\n', '\n```'); break;
        case 'math':          wrapSelection(ctx, '$', '$'); break;
        case 'mathblock':     wrapBlock(ctx, '$$\n', '\n$$'); break;
        case 'quote':         toggleLinePrefix(ctx, '> '); break;
        case 'hr':            insertAtCursor(ctx, '\n\n---\n\n'); break;
        case 'table':         insertTable(ctx); break;
        default: {
            // Check custom tools
            const tool = getCustomTools().find(t => t.action === action);
            if (tool && typeof tool.handler === 'function') {
                tool.handler(ctx.instance);
            }
            break;
        }
    }
    onInput(ctx);
}

// ═══════════════════════════════════════════════════
// Selection Management
// ═══════════════════════════════════════════════════

/** Save the current selection range for later restoration. */
export function saveSelection(ctx) {
    const sel = window.getSelection();
    if (sel.rangeCount > 0) {
        ctx.savedRange = sel.getRangeAt(0).cloneRange();
    }
}

/** Restore a previously saved selection range. */
export function restoreSelection(ctx) {
    if (!ctx.savedRange) return;
    const sel = window.getSelection();
    sel.removeAllRanges();
    sel.addRange(ctx.savedRange);
    ctx.savedRange = null;
}

// ═══════════════════════════════════════════════════
// Textarea Text Manipulation
// ═══════════════════════════════════════════════════

/**
 * Wrap the current selection with before/after strings.
 * If nothing is selected, insert both and place cursor between them.
 * @param {object} ctx
 * @param {string} before
 * @param {string} after
 */
export function wrapSelection(ctx, before, after) {
    const ta = ctx.textarea;
    const start = ta[0].selectionStart;
    const end = ta[0].selectionEnd;
    const text = ta.val();
    const selected = text.substring(start, end);

    if (selected) {
        // Check if already wrapped — toggle off
        const bLen = before.length;
        const aLen = after.length;
        if (start >= bLen && text.substring(start - bLen, start) === before &&
            text.substring(end, end + aLen) === after) {
            ta.val(text.substring(0, start - bLen) + selected + text.substring(end + aLen));
            ta[0].selectionStart = start - bLen;
            ta[0].selectionEnd = end - bLen;
            return;
        }
        ta.val(text.substring(0, start) + before + selected + after + text.substring(end));
        ta[0].selectionStart = start + before.length;
        ta[0].selectionEnd = end + before.length;
    } else {
        ta.val(text.substring(0, start) + before + after + text.substring(end));
        ta[0].selectionStart = ta[0].selectionEnd = start + before.length;
    }
}

/**
 * Toggle a line prefix (heading, list, blockquote).
 * If the current line already has the prefix, remove it. Otherwise, set it.
 * @param {object} ctx
 * @param {string} prefix
 */
export function toggleLinePrefix(ctx, prefix) {
    const ta = ctx.textarea;
    const text = ta.val();
    const start = ta[0].selectionStart;

    // Find the start of the current line
    let lineStart = text.lastIndexOf('\n', start - 1) + 1;
    let lineEnd = text.indexOf('\n', start);
    if (lineEnd === -1) lineEnd = text.length;
    const currentLine = text.substring(lineStart, lineEnd);

    // Check if line already has this prefix
    if (currentLine.startsWith(prefix)) {
        // Remove prefix
        ta.val(text.substring(0, lineStart) + currentLine.substring(prefix.length) + text.substring(lineEnd));
        ta[0].selectionStart = ta[0].selectionEnd = start - prefix.length;
    } else {
        // Remove any existing heading/list prefix before adding new one
        const stripped = currentLine.replace(/^(#{1,6}\s|[-*+]\s(\[[ xX]\]\s)?|\d+\.\s|>\s?)/, '');
        ta.val(text.substring(0, lineStart) + prefix + stripped + text.substring(lineEnd));
        ta[0].selectionStart = ta[0].selectionEnd = lineStart + prefix.length + stripped.length;
    }
}

/**
 * Wrap the selection (or empty cursor position) with block-level delimiters on new lines.
 * @param {object} ctx
 * @param {string} before
 * @param {string} after
 */
export function wrapBlock(ctx, before, after) {
    const ta = ctx.textarea;
    const start = ta[0].selectionStart;
    const end = ta[0].selectionEnd;
    const text = ta.val();
    const selected = text.substring(start, end) || '';
    const insert = '\n' + before + selected + after + '\n';
    ta.val(text.substring(0, start) + insert + text.substring(end));
    ta[0].selectionStart = start + 1 + before.length;
    ta[0].selectionEnd = ta[0].selectionStart + selected.length;
}

/**
 * Insert text at the current cursor position.
 * @param {object} ctx
 * @param {string} text
 */
export function insertAtCursor(ctx, text) {
    const ta = ctx.textarea;
    const start = ta[0].selectionStart;
    const end = ta[0].selectionEnd;
    ta.val(v => v.substring(0, start) + text + v.substring(end));
    ta[0].selectionStart = ta[0].selectionEnd = start + text.length;
}

/**
 * Prompt for a URL and insert a Markdown link.
 * @param {object} ctx
 */
function insertLink(ctx) {
    const ta = ctx.textarea;
    const selected = ta.val().substring(ta[0].selectionStart, ta[0].selectionEnd);
    const url = prompt('Enter URL:', 'https://');
    if (!url) return;
    const label = selected || 'link text';
    const start = ta[0].selectionStart;
    const end = ta[0].selectionEnd;
    const md = `[${label}](${url})`;
    ta.val(v => v.substring(0, start) + md + v.substring(end));
    ta[0].selectionStart = start + 1;
    ta[0].selectionEnd = start + 1 + label.length;
}

/**
 * Prompt for a URL and insert a Markdown image.
 * @param {object} ctx
 */
function insertImage(ctx) {
    const url = prompt('Enter image URL:', 'https://');
    if (!url) return;
    const alt = prompt('Alt text:', 'image') || 'image';
    insertAtCursor(ctx, `![${alt}](${url})`);
}

/**
 * Insert a 3-column table template.
 * @param {object} ctx
 */
function insertTable(ctx) {
    const table = '\n| Header | Header | Header |\n| ------ | ------ | ------ |\n| Cell   | Cell   | Cell   |\n| Cell   | Cell   | Cell   |\n';
    insertAtCursor(ctx, table);
}

// ═══════════════════════════════════════════════════
// WYSIWYG Mode Actions (Selection / Range API)
// ═══════════════════════════════════════════════════

/**
 * Toggle an inline format tag (strong, em, del) around the selection.
 * @param {object} ctx
 * @param {string} tagName
 */
function wysiwygToggleInline(ctx, tagName) {
    const sel = window.getSelection();
    if (!sel.rangeCount) return;
    const range = sel.getRangeAt(0);
    if (!ctx.preview.contains(range.commonAncestorContainer)) return;

    // Already wrapped? → unwrap
    let ancestor = range.commonAncestorContainer;
    if (ancestor.nodeType === Node.TEXT_NODE) ancestor = razyui(ancestor).parent()[0];
    const wrap = razyui(ancestor).closest(tagName)[0];
    if (wrap && ctx.preview.contains(wrap)) {
        const parent = wrap.parentNode;
        while (wrap.firstChild) parent.insertBefore(wrap.firstChild, wrap);
        parent.removeChild(wrap);
        parent.normalize();
        return;
    }

    if (range.collapsed) return;

    const el = razyui.el(tagName);
    try { range.surroundContents(el[0]); } catch {
        el.append(range.extractContents());
        range.insertNode(el[0]);
    }
    sel.removeAllRanges();
    const r = document.createRange();
    r.selectNodeContents(el[0]);
    sel.addRange(r);
}

/**
 * Format the block containing the cursor (h1-h3, blockquote, p).
 * @param {object} ctx
 * @param {string} tagName
 */
function wysiwygFormatBlock(ctx, tagName) {
    const sel = window.getSelection();
    if (!sel.rangeCount) return;
    const range = sel.getRangeAt(0);
    if (!ctx.preview.contains(range.commonAncestorContainer)) return;

    let block = razyui(range.startContainer);
    if (block[0].nodeType === Node.TEXT_NODE) block = block.parent();
    const tags = ['P', 'H1', 'H2', 'H3', 'H4', 'H5', 'H6', 'DIV', 'BLOCKQUOTE'];
    block = block.closest(tags.join(','), ctx.preview);
    if (!block.length) {
        const nb = razyui.el(tagName);
        if (range.collapsed) { nb.html('<br>'); } else { nb.append(range.extractContents()); }
        range.insertNode(nb[0]);
        return;
    }

    const target = tagName.toUpperCase();
    const newTag = block[0].tagName === target ? 'p' : tagName;
    const nb = razyui.el(newTag, { innerHTML: block.html() });
    block[0].replaceWith(nb[0]);
    sel.removeAllRanges();
    const r = document.createRange();
    r.selectNodeContents(nb[0]);
    r.collapse(false);
    sel.addRange(r);
}

/**
 * Insert an HTML fragment at the current cursor position.
 * @param {object} ctx
 * @param {string} html
 */
export function wysiwygInsertHTML(ctx, html) {
    ctx.preview.focus();
    const sel = window.getSelection();
    let range;
    if (sel.rangeCount && ctx.preview.contains(sel.getRangeAt(0).commonAncestorContainer)) {
        range = sel.getRangeAt(0);
    } else {
        range = document.createRange();
        range.selectNodeContents(ctx.preview[0]);
        range.collapse(false);
    }
    range.deleteContents();
    const tpl = razyui.el('template', { innerHTML: html });
    const frag = tpl[0].content;
    const last = frag.lastChild;
    range.insertNode(frag);
    if (last) {
        const r = document.createRange();
        r.setStartAfter(last);
        r.collapse(true);
        sel.removeAllRanges();
        sel.addRange(r);
    }
}

/**
 * Insert plain text at the current cursor position.
 * @param {object} ctx
 * @param {string} text
 */
export function wysiwygInsertText(ctx, text) {
    ctx.preview.focus();
    const sel = window.getSelection();
    let range;
    if (sel.rangeCount && ctx.preview.contains(sel.getRangeAt(0).commonAncestorContainer)) {
        range = sel.getRangeAt(0);
    } else {
        range = document.createRange();
        range.selectNodeContents(ctx.preview[0]);
        range.collapse(false);
    }
    range.deleteContents();
    const node = document.createTextNode(text);
    range.insertNode(node);
    const r = document.createRange();
    r.setStartAfter(node);
    r.collapse(true);
    sel.removeAllRanges();
    sel.addRange(r);
}

/**
 * Toggle an ordered / unordered list for the current block.
 * @param {object} ctx
 * @param {string} listTag — 'ul' or 'ol'
 */
function wysiwygToggleList(ctx, listTag) {
    const sel = window.getSelection();
    if (!sel.rangeCount) return;
    const range = sel.getRangeAt(0);
    if (!ctx.preview.contains(range.commonAncestorContainer)) return;

    let node = range.startContainer;
    if (node.nodeType === Node.TEXT_NODE) node = razyui(node).parent()[0];

    // Already in this list type? → unwrap to <p>
    const existing = node?.closest?.(listTag);
    if (existing && ctx.preview.contains(existing)) {
        const frag = document.createDocumentFragment();
        for (const li of Array.from(existing.children)) {
            if (li.tagName === 'LI') {
                const p = razyui.el('p', { innerHTML: li.innerHTML });
                frag.appendChild(p[0]);
            }
        }
        existing.replaceWith(frag);
        return;
    }

    // In opposite list type? → switch
    const other = node?.closest?.(listTag === 'ul' ? 'ol' : 'ul');
    if (other && ctx.preview[0].contains(other)) {
        const nl = razyui.el(listTag, { innerHTML: other.innerHTML });
        other.replaceWith(nl[0]);
        return;
    }

    // Convert current block to list
    const blockTags = ['P', 'H1', 'H2', 'H3', 'H4', 'H5', 'H6', 'DIV'];
    const block = razyui(node).closest(blockTags.join(','), ctx.preview);
    const list = razyui.el(listTag);
    const li = razyui.el('li');
    if (block.length) {
        li.html(block.html());
        list.append(li);
        block[0].replaceWith(list[0]);
    } else {
        li.html('<br>');
        list.append(li);
        range.insertNode(list[0]);
    }
}

/**
 * Toggle inline code wrap in WYSIWYG mode.
 * @param {object} ctx
 */
function wysiwygToggleCode(ctx) {
    const sel = window.getSelection();
    if (!sel.rangeCount) return;
    const range = sel.getRangeAt(0);
    if (!ctx.preview.contains(range.commonAncestorContainer)) return;

    // Check if inside a <code> (not in <pre>)
    let parent = range.commonAncestorContainer;
    if (parent.nodeType === Node.TEXT_NODE) parent = parent.parentElement;
    const codeWrap = razyui(parent).closest('code')[0];
    if (codeWrap && codeWrap.parentElement?.nodeName !== 'PRE' && ctx.preview.contains(codeWrap)) {
        const textNode = document.createTextNode(codeWrap.textContent);
        codeWrap.replaceWith(textNode);
        return;
    }

    // Wrap selection in <code>
    if (!sel.isCollapsed) {
        const code = razyui.el('code');
        try {
            range.surroundContents(code[0]);
        } catch {
            const contents = range.extractContents();
            code.append(contents);
            range.insertNode(code[0]);
        }
    }
}

/**
 * Handle an action in WYSIWYG mode using Selection / Range API.
 * @param {object} ctx
 * @param {string} action
 */
function handleWysiwygAction(ctx, action) {
    switch (action) {
        case 'bold':          wysiwygToggleInline(ctx, 'strong'); break;
        case 'italic':        wysiwygToggleInline(ctx, 'em'); break;
        case 'strikethrough': wysiwygToggleInline(ctx, 'del'); break;
        case 'h1':            wysiwygFormatBlock(ctx, 'h1'); break;
        case 'h2':            wysiwygFormatBlock(ctx, 'h2'); break;
        case 'h3':            wysiwygFormatBlock(ctx, 'h3'); break;
        case 'ul':            wysiwygToggleList(ctx, 'ul'); break;
        case 'ol':            wysiwygToggleList(ctx, 'ol'); break;
        case 'task':          wysiwygToggleList(ctx, 'ul'); break;
        case 'quote':         wysiwygFormatBlock(ctx, 'blockquote'); break;
        case 'hr':            wysiwygInsertHTML(ctx, '<hr>'); break;
        case 'code':          wysiwygToggleCode(ctx); break;
        case 'codeblock':
            wysiwygInsertHTML(ctx, '<pre><code>code here</code></pre>');
            break;
        case 'math': {
            const sel = window.getSelection();
            const expr = sel.toString() || 'x^2';
            wysiwygInsertHTML(ctx, `<span class="math-inline" data-math="${expr}">${expr}</span>`);
            break;
        }
        case 'mathblock':
            wysiwygInsertHTML(ctx, '<div class="math-block" data-math="E = mc^2">E = mc^2</div>');
            break;
        case 'link': {
            const sel = window.getSelection();
            const text = sel.toString() || 'link';
            const url = prompt('Enter URL:', 'https://');
            if (url) {
                wysiwygInsertHTML(ctx,
                    `<a href="${url}" target="_blank" rel="noopener">${text}</a>`);
            }
            break;
        }
        case 'image': {
            const url = prompt('Enter image URL:', 'https://');
            if (!url) break;
            const alt = prompt('Alt text:', 'image') || 'image';
            wysiwygInsertHTML(ctx, `<img src="${url}" alt="${alt}">`);
            break;
        }
        case 'table': {
            const html = '<table><thead><tr><th>Header</th><th>Header</th><th>Header</th></tr></thead>' +
                '<tbody><tr><td>Cell</td><td>Cell</td><td>Cell</td></tr>' +
                '<tr><td>Cell</td><td>Cell</td><td>Cell</td></tr></tbody></table>';
            wysiwygInsertHTML(ctx, html);
            break;
        }
        default: {
            const tool = getCustomTools().find(t => t.action === action);
            if (tool && typeof tool.handler === 'function') {
                tool.handler(ctx.instance);
            }
            break;
        }
    }
    onWysiwygInput(ctx);
}

// ═══════════════════════════════════════════════════
// Update Cycle
// ═══════════════════════════════════════════════════

/**
 * Handle input in the textarea (standard mode).
 * @param {object} ctx
 */
export function onInput(ctx) {
    if (!ctx.textarea) return;
    const md = ctx.textarea.val();
    ctx.setState({ markdown: md });

    // Sync back to original textarea if applicable
    if (ctx.target.tagName === 'TEXTAREA') {
        ctx.target.value = md;
    }

    // Debounced preview + status update
    clearTimeout(ctx.updateTimer);
    ctx.updateTimer = setTimeout(() => {
        ctx.updatePreview();
        ctx.updateStatus();
    }, 120);

    if (typeof ctx.config.onChange === 'function') {
        ctx.config.onChange(md);
    }
}

/**
 * Handle input in WYSIWYG mode — sync HTML → Markdown state.
 * @param {object} ctx
 */
export function onWysiwygInput(ctx) {
    const html = ctx.preview.html();
    const md = htmlToMarkdown(html);
    ctx.setState({ markdown: md });

    // Manage placeholder
    if (!ctx.preview.text().trim()) {
        ctx.preview.attr('data-placeholder', ctx.config.placeholder);
    } else {
        ctx.preview.removeAttr('data-placeholder');
    }

    if (typeof ctx.config.onChange === 'function') {
        ctx.config.onChange(md);
    }
}

// ═══════════════════════════════════════════════════
// Mode & Fullscreen
// ═══════════════════════════════════════════════════

/**
 * Switch the editor view mode.
 * @param {object} ctx
 * @param {string} mode — 'editor' | 'split' | 'preview' | 'wysiwyg'
 */
export function setMode(ctx, mode) {
    if (!['editor', 'split', 'preview', 'wysiwyg'].includes(mode)) return;

    const prevMode = ctx.stateRef.mode;

    // Leaving WYSIWYG: convert HTML back to markdown in textarea
    if (prevMode === 'wysiwyg' && mode !== 'wysiwyg' && ctx.textarea) {
        ctx.textarea.val(htmlToMarkdown(ctx.preview.html()));
        ctx.preview.prop('contentEditable', 'false');
        ctx.setState({ markdown: ctx.textarea.val() });
    }

    // Entering WYSIWYG: render markdown as HTML in contenteditable preview
    if (mode === 'wysiwyg' && prevMode !== 'wysiwyg') {
        ctx.preview.html(parse(
            ctx.textarea ? ctx.textarea.val() : ctx.stateRef.markdown
        ));
        ctx.preview.prop('contentEditable', 'true');
    }

    // Leaving WYSIWYG: remove contentEditable if not already done
    if (prevMode === 'wysiwyg' && mode !== 'wysiwyg') {
        ctx.preview.prop('contentEditable', 'false');
    }

    ctx.setState({ mode });
    ctx.container.attr('class', `markdown-editor md-editor mode-${mode}${ctx.stateRef.fullscreen ? ' is-fullscreen' : ''}${ctx.config.lite ? ' is-lite' : ''}`);
    PART.ROOT.apply(ctx.container);
    // Update mode button active states & disable toolbar in preview mode
    if (ctx.toolbar) {
        ctx.toolbar.find('.md-mode-btn').each(btn => {
            razyui(btn).toggleClass('is-active', btn.dataset.mode === mode);
        });
        ctx.toolbar.find('.md-toolbar-btn:not(.md-mode-btn)').each(btn => {
            btn.disabled = mode === 'preview';
            razyui(btn).css('opacity', mode === 'preview' ? '0.4' : '')
                       .css('pointer-events', mode === 'preview' ? 'none' : '');
        });
    }

    // Refresh preview when switching to split/preview
    if (mode === 'split' || mode === 'preview') {
        ctx.updatePreview();
    }
}

/**
 * Toggle fullscreen mode.
 * @param {object} ctx
 */
export function toggleFullscreen(ctx) {
    const fs = !ctx.stateRef.fullscreen;
    ctx.setState({ fullscreen: fs });
    ctx.container.toggleClass('is-fullscreen', fs);
}

// ═══════════════════════════════════════════════════
// Convenience Helpers
// ═══════════════════════════════════════════════════

/**
 * Get the current markdown content regardless of mode.
 * @param {object} ctx
 * @returns {string}
 */
export function getCurrentMarkdown(ctx) {
    if (ctx.config.lite || ctx.stateRef.mode === 'wysiwyg') {
        return htmlToMarkdown(ctx.preview.html());
    }
    return ctx.textarea ? ctx.textarea.val() : ctx.stateRef.markdown;
}

/**
 * Restore markdown content from a string.
 * @param {object} ctx
 * @param {string} md
 */
export function applyMarkdown(ctx, md) {
    if (ctx.config.lite || ctx.stateRef.mode === 'wysiwyg') {
        ctx.preview.html(parse(md));
        onWysiwygInput(ctx);
    } else {
        ctx.textarea.val(md);
        onInput(ctx);
    }
}

// ═══════════════════════════════════════════════════
// Delegated Event Binding
// ═══════════════════════════════════════════════════

/**
 * Single delegated click listener on the editor container that handles
 * toolbar button clicks (formatting, mode, fullscreen) and context-menu
 * item clicks.  Replaces per-button addEventListener calls in view.js.
 * @param {object} ctx
 */
function bindToolbarAndMenuEvents(ctx) {
    ctx.container.on('click', (e) => {
        // ── Toolbar button ──
        const toolbarBtn = razyui(e.target).closest('.md-toolbar-btn');
        if (toolbarBtn.length && ctx.toolbar?.[0].contains(toolbarBtn[0])) {
            // Mode toggle
            if (toolbarBtn.data('mode')) {
                ctx.setMode(toolbarBtn.data('mode'));
                return;
            }
            // Fullscreen
            if (toolbarBtn.data('role') === 'fullscreen') {
                ctx.toggleFullscreen();
                return;
            }
            // History menu toggle
            if (toolbarBtn.data('role') === 'history-toggle') {
                const menu = ctx.toolbar.find('.md-history-menu');
                if (menu.length) menu.toggleClass('is-open');
                return;
            }
            // Formatting / custom action
            if (toolbarBtn.data('action')) {
                e.preventDefault();
                ctx.handleAction(toolbarBtn.data('action'));
                (ctx.textarea?.[0] || ctx.preview[0]).focus();
            }
            return;
        }

        // ── History menu item ──
        const histItem = razyui(e.target).closest('.md-history-menu-item');
        if (histItem.length && ctx.toolbar?.[0].contains(histItem[0])) {
            const action = histItem.data('history');
            // Close menu
            ctx.toolbar.find('.md-history-menu').removeClass('is-open');
            if (action === 'save') {
                const saved = ctx.pushHistory(ctx.getCurrentMarkdown());
                if (!saved) razyui.load('Dialog').then(D => D.alert(Icons.svg('save', { size: 16, strokeWidth: 1.5 }) + ' Save', 'Content unchanged — nothing to save.'));
            } else if (action === 'manage') {
                ctx.showHistoryManagerPopup();
            } else if (action === 'restore') {
                ctx.showHistoryRestorePopup();
            } else if (action === 'clear') {
                razyui.load('Dialog').then(D => {
                    D.confirm(Icons.svg('trash-2', { size: 16, strokeWidth: 1.5 }) + ' Clear History', 'Delete all snapshots in the active set?').then(ok => {
                        if (ok) {
                            ctx.clearActiveHistory();
                        }
                    });
                });
            }
            return;
        }

        // ── Context-menu item ──
        const ctxItem = razyui(e.target).closest('.md-context-item[data-action]');
        if (ctxItem.length && ctx.contextMenu?.[0].contains(ctxItem[0])) {
            e.preventDefault();
            e.stopPropagation();
            ctx.hideContextMenu();
            ctx.restoreSelection();
            ctx.handleAction(ctxItem.dataset.action);
            (ctx.textarea?.[0] || ctx.preview[0]).focus();
        }
    });
}

/**
 * Bind delegated events on the history-restore overlay.
 * @param {object}   ctx
 * @param {HTMLElement} overlay
 * @param {object}   refs
 * @param {object}   refs.book            — history book object
 * @param {function} refs.getActiveSetId   — returns current active set ID
 * @param {object}   refs.snapCombobox   — Combobox instance for snapshots
 * @param {function} refs.updatePreviewText — refresh the preview text area
 */
export function bindHistoryRestoreEvents(ctx, overlay, refs) {
    overlay.on('click', (e) => {
        // Click on overlay background (outside panel)
        if (e.target === overlay[0]) {
            ctx.pushHistory(ctx.getCurrentMarkdown());
            overlay[0].remove();
            return;
        }

        const btn = razyui(e.target).closest('[data-role]');
        if (!btn.length) return;

        switch (btn.data('role')) {
            case 'restore': {
                const activeSetId = refs.getActiveSetId();
                if (String(refs.book.activeSet) !== activeSetId) {
                    refs.book.activeSet = parseInt(activeSetId, 10);
                    ctx.writeBook(refs.book);
                }
                const snaps = refs.book.sets[activeSetId]?.snapshots || [];
                const idx = parseInt(refs.snapCombobox.getValue(), 10);
                if (!isNaN(idx) && snaps[idx]) {
                    ctx.applyMarkdown(snaps[idx].md);
                }
                overlay[0].remove();
                break;
            }
            case 'manage':
                overlay[0].remove();
                ctx.showHistoryManagerPopup();
                break;
            case 'dismiss':
                ctx.pushHistory(ctx.getCurrentMarkdown());
                overlay[0].remove();
                break;
        }
    });

    overlay.on('change', (e) => {
        if (e.target.dataset.role === 'snap-select') {
            refs.updatePreviewText();
        }
    });
}

/**
 * Bind delegated events on the history-manager wrapper.
 * Survives wrap.innerHTML re-renders triggered by renderAll().
 * @param {object}   ctx
 * @param {HTMLElement} wrap
 * @param {object}   refs
 * @param {object}   refs.Dialog          — Dialog class for prompts/confirms
 * @param {function} refs.getBook         — returns fresh history book from storage
 * @param {function} refs.getActiveTab    — returns current active tab ID
 * @param {function} refs.setActiveTab    — sets the active tab ID
 * @param {function} refs.renderAll       — rebuild the manager content
 * @param {function} refs.getPopupCtrl    — returns the Dialog control for closing
 */
export function bindHistoryManagerEvents(ctx, wrap, refs) {
    wrap.on('click', async (e) => {
        const btn = razyui(e.target).closest('[data-role]');
        if (!btn.length) return;

        const Dialog = refs.Dialog;
        const book = refs.getBook();

        switch (btn.data('role')) {
            case 'tab':
                refs.setActiveTab(btn.data('setId'));
                refs.renderAll();
                break;

            case 'add-set': {
                const name = await Dialog.prompt('New Set', 'Enter a name for the new history set:');
                if (name === null) return;
                const ids = Object.keys(book.sets);
                const newId = String(Math.max(0, ...ids.map(Number).filter(n => !isNaN(n))) + 1);
                book.sets[newId] = { name: name || 'Set ' + newId, created: Date.now(), snapshots: [] };
                ctx.writeBook(book);
                refs.setActiveTab(newId);
                refs.renderAll();
                break;
            }

            case 'switch-set':
                book.activeSet = parseInt(refs.getActiveTab(), 10);
                ctx.writeBook(book);
                refs.renderAll();
                break;

            case 'rename-set': {
                const activeTab = refs.getActiveTab();
                const activeSet = book.sets[activeTab];
                const name = await Dialog.prompt('Rename Set', 'New name:', { defaultValue: activeSet.name });
                if (name === null) return;
                activeSet.name = name || 'Set ' + activeTab;
                ctx.writeBook(book);
                refs.renderAll();
                break;
            }

            case 'delete-set': {
                const activeTab = refs.getActiveTab();
                const activeSet = book.sets[activeTab];
                const ok = await Dialog.confirm('Delete Set', 'Delete "' + (activeSet.name || 'Set ' + activeTab) + '" and all its snapshots?');
                if (!ok) return;
                delete book.sets[activeTab];
                if (String(book.activeSet) === activeTab) {
                    book.activeSet = parseInt(Object.keys(book.sets)[0], 10) || 0;
                }
                ctx.writeBook(book);
                refs.setActiveTab(String(book.activeSet));
                refs.renderAll();
                break;
            }

            case 'restore-snap': {
                const activeTab = refs.getActiveTab();
                const idx = parseInt(btn.data('index'), 10);
                const activeSet = book.sets[activeTab];
                if (activeSet && !isNaN(idx) && activeSet.snapshots[idx]) {
                    ctx.applyMarkdown(activeSet.snapshots[idx].md);
                    const ctrl = refs.getPopupCtrl();
                    if (ctrl) ctrl.close();
                }
                break;
            }

            case 'delete-snap': {
                const activeTab = refs.getActiveTab();
                const idx = parseInt(btn.data('index'), 10);
                const activeSet = book.sets[activeTab];
                if (activeSet && !isNaN(idx)) {
                    activeSet.snapshots.splice(idx, 1);
                    ctx.writeBook(book);
                    refs.renderAll();
                }
                break;
            }
        }
    });
}
